// mcp/http-handler.ts
var fileDeps = {
  getLibrary: () => library,
  getMeasures: () => seedMeasures
};
function createMcpHandler(deps = fileDeps) {
  return async function handleMcpRequest2(request) {
    const user = await authedUserFromHeader(request.headers.get("authorization"));
    const [library2, measures] = await Promise.all([deps.getLibrary(), deps.getMeasures(user)]);
    const getSeedMeasure = (id) => measures.find((m) => m.id === id);
    const server = buildServer({ user, library: library2, seedMeasures: measures, getSeedMeasure });
    const transport = new WebStandardStreamableHTTPServerTransport({
      sessionIdGenerator: void 0,
      enableJsonResponse: true
    });
    await server.connect(transport);
    try {
      return await transport.handleRequest(request);
    } finally {
      await transport.close();
      await server.close();
    }
  };
}
var handleMcpRequest = createMcpHandler();

// src/lib/measure/load-supabase.ts
var num = (v) => typeof v === "number" ? v : Number(v);
async function loadLibrary(db) {
  const tables = ["objects", "resources", "products", "refs", "subsectors", "indicators"];
  const [objects, resources, products, refs, subsectors, indicators] = await Promise.all(
    tables.map((t) => db.from(t).select("*"))
  );
  for (const [i, r] of [objects, resources, products, refs, subsectors, indicators].entries()) {
    if (r.error) throw new Error(`load ${tables[i]}: ${r.error.message}`);
  }
  const [units, bridges] = await Promise.all([db.from("units").select("*"), db.from("bridges").select("*")]);
  const unitRows = units.error ? [] : units.data ?? [];
  const bridgeRows = bridges.error ? [] : bridges.data ?? [];
  const graph = {
    objects: (objects.data ?? []).map((o) => ({
      id: o.id,
      name: o.name,
      kind: o.kind,
      description: o.description ?? void 0,
      rules: o.rules ?? void 0,
      lifetimeYrs: o.lifetime_yrs != null ? num(o.lifetime_yrs) : void 0
    })),
    resources: (resources.data ?? []).map((r) => ({ id: r.id, name: r.name, unit: r.unit })),
    products: (products.data ?? []).map((p) => ({
      id: p.id,
      name: p.name,
      unit: p.unit,
      service_unit: p.service_unit ?? void 0,
      sector_ref: p.sector_ref ?? void 0,
      technology_ref: p.technology_ref ?? void 0
    })),
    references: (refs.data ?? []).map((r) => ({
      id: r.id,
      type: r.type ?? "",
      range: [num(r.range_min), num(r.range_max)],
      unit: r.unit ?? "",
      source: r.source ?? void 0
    })),
    subsectors: (subsectors.data ?? []).map((s) => ({ id: s.id, sector_ref: s.sector_ref, name: s.name })),
    indicators: (indicators.data ?? []).map((i) => ({
      id: i.id,
      key: i.key,
      owner_kind: i.owner_kind,
      owner_ref: i.owner_ref,
      value: num(i.value),
      unit: i.unit ?? void 0,
      reference_ref: i.reference_ref ?? void 0,
      provenance: i.provenance ?? void 0
    })),
    units: unitRows.map((u) => ({ id: u.id, dim: u.dim ?? {}, scale: num(u.scale) })),
    bridges: bridgeRows.map((b) => ({
      id: b.id,
      from: b.from,
      via: b.via ?? [],
      to: b.to,
      expr: b.expr,
      carrier_rule: b.carrier_rule ?? void 0,
      authoring: b.authoring ?? ""
    }))
  };
  return assembleLibrary(graph);
}
async function loadMeasures(db) {
  const { data, error } = await db.from("measures").select("data");
  if (error) throw new Error(`load measures: ${error.message}`);
  return (data ?? []).map((r) => r.data);
}

// supabase/functions/mcp/server-entry.ts
var SUPABASE_URL = Deno.env.get("SUPABASE_URL");
var ANON_KEY = Deno.env.get("SUPABASE_ANON_KEY");
var anon = createClient2(SUPABASE_URL, ANON_KEY, { auth: { persistSession: false } });
var libraryCache = null;
var handle = createMcpHandler({
  getLibrary: async () => libraryCache ??= await loadLibrary(anon),
  getMeasures: async (user) => loadMeasures(user?.client ?? anon)
});
Deno.serve(handle);
